'use strict';

/**
* Fill a strided array with linearly spaced numeric elements which increment by `1` starting from a specified value.
*
* @module @stdlib/blas/ext/base/gunitspace
*
* @example
* import gunitspace from '@stdlib/blas/ext/base/gunitspace';
*
* var x = [ 0.0, 0.0, 0.0, 0.0 ];
*
* gunitspace( x.length, 3.0, x, 1 );
* // x => [ 3.0, 4.0, 5.0, 6.0 ]
*
* @example
* import gunitspace from '@stdlib/blas/ext/base/gunitspace';
*
* var x = [ 0.0, 0.0, 0.0, 0.0 ];
*
* gunitspace.ndarray( x.length, 3.0, x, 1, 0 );
* // x => [ 3.0, 4.0, 5.0, 6.0 ]
*/

// MODULES //

import setReadOnly from '@stdlib/utils/define-nonenumerable-read-only-property';
import main from './main.js';
import ndarray from './ndarray.js';


// MAIN //

setReadOnly( main, 'ndarray', ndarray );


// EXPORTS //

export default main;
