'use strict';

// MODULES //

import numelDimension from '@stdlib/ndarray/base/numel-dimension';
import getStride from '@stdlib/ndarray/base/stride';
import getOffset from '@stdlib/ndarray/base/offset';
import getData from '@stdlib/ndarray/base/data-buffer';
import ndarraylike2scalar from '@stdlib/ndarray/base/ndarraylike2scalar';
import { ndarray as strided } from './../../../../../ext/base/gunitspace';


// MAIN //

/**
* Fills a one-dimensional ndarray with linearly spaced numeric elements which increment by `1` starting from a specified value.
*
* ## Notes
*
* -   The function expects the following ndarrays:
*
*     -   a one-dimensional input ndarray.
*     -   a zero-dimensional ndarray containing a starting value.
*
* @param {ArrayLikeObject<Object>} arrays - array-like object containing ndarrays
* @returns {ndarray} input ndarray
*
* @example
* import vector from '@stdlib/ndarray/vector/ctor';
* import scalar2ndarray from '@stdlib/ndarray/from-scalar';
*
* var x = vector( [ 0.0, 0.0, 0.0, 0.0 ], 'generic' );
* // returns <ndarray>[ 0.0, 0.0, 0.0, 0.0 ]
*
* var start = scalar2ndarray( 3.0, {
*     'dtype': 'generic'
* });
*
* var out = gunitspace( [ x, start ] );
* // returns <ndarray>[ 3.0, 4.0, 5.0, 6.0 ]
*/
function gunitspace( arrays ) {
	var start = ndarraylike2scalar( arrays[ 1 ] );
	var x = arrays[ 0 ];
	strided( numelDimension( x, 0 ), start, getData( x ), getStride( x, 0 ), getOffset( x ) ); // eslint-disable-line max-len
	return x;
}


// EXPORTS //

export default gunitspace;
