'use strict';

// MODULES //

import stride2offset from '@stdlib/strided/base/stride2offset';
import ndarray from './ndarray.js';


// MAIN //

/**
* Computes the number of non-`NaN` elements in a strided array.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {NumericArray} x - input array
* @param {integer} strideX - stride length
* @returns {NonNegativeInteger} count
*
* @example
* var x = [ 1.0, -2.0, NaN, 2.0 ];
*
* var v = gnancount( x.length, x, 1 );
* // returns 3
*/
function gnancount( N, x, strideX ) {
	return ndarray( N, x, strideX, stride2offset( N, strideX ) );
}


// EXPORTS //

export default gnancount;
