'use strict';

// MODULES //

import numelDimension from '@stdlib/ndarray/base/numel-dimension';
import getStride from '@stdlib/ndarray/base/stride';
import getOffset from '@stdlib/ndarray/base/offset';
import getData from '@stdlib/ndarray/base/data-buffer';
import { ndarray as strided } from './../../../../../ext/base/daxpb';
import ndarraylike2scalar from '@stdlib/ndarray/base/ndarraylike2scalar';


// MAIN //

/**
* Multiplies each element in a one-dimensional double-precision floating-point ndarray by a scalar constant and adds a scalar constant to each result.
*
* ## Notes
*
* -   The function expects the following ndarrays:
*
*     -   a one-dimensional input ndarray.
*     -   a zero-dimensional ndarray containing the scalar constant to multiply.
*     -   a zero-dimensional ndarray containing the scalar constant to add.
*
* @param {ArrayLikeObject<Object>} arrays - array-like object containing ndarrays
* @returns {ndarray} input ndarray
*
* @example
* import Float64Vector from '@stdlib/ndarray/vector/float64';
* import scalar2ndarray from '@stdlib/ndarray/from-scalar';
*
* var x = new Float64Vector( [ -2.0, 1.0, 3.0, -5.0 ] );
*
* var alpha = scalar2ndarray( 5.0, {
*     'dtype': 'float64'
* });
*
* var beta = scalar2ndarray( 3.0, {
*     'dtype': 'float64'
* });
*
* var out = daxpb( [ x, alpha, beta ] );
* // returns <ndarray>[ -7.0, 8.0, 18.0, -22.0 ]
*/
function daxpb( arrays ) {
	var alpha;
	var beta;
	var x;

	x = arrays[ 0 ];
	alpha = ndarraylike2scalar( arrays[ 1 ] );
	beta = ndarraylike2scalar( arrays[ 2 ] );
	strided( numelDimension( x, 0 ), alpha, beta, getData( x ), getStride( x, 0 ), getOffset( x ) ); // eslint-disable-line max-len
	return x;
}


// EXPORTS //

export default daxpb;
